mapper.update:
UPDATE receive_notice
FBillNo = #{fBillNo}, FDocumentStatus = #{fDocumentStatus}, FBillTypeID = #{fBillTypeID}, FDate = #{fDate}, FReceiveDeptId = #{fReceiveDeptId}, FPurOrgId = #{fPurOrgId}, FReceiverId = #{fReceiverId}, F_jcf = #{fjcf}, FSupplierId = #{fSupplierId}, F_gcbz = #{fgcbz}, F_shdz = #{fshdz}, F_DATE_jz = #{fDATEjz}, F_djtjcf = #{fdjtjcf}, FSupplyId = #{fSupplyId}, FProviderContactId = #{fProviderContactId}, FSupplyAddress = #{fSupplyAddress}, FSettleId = #{fSettleId}, FChargeId = #{fChargeId}, FSettleModeId = #{fSettleModeId}, FPayConditionId = #{fPayConditionId}, FSettleCurrId = #{fSettleCurrId}, FAllDisCount = #{fAllDisCount}, FCreatorId = #{fCreatorId}, FCreateDate = #{fCreateDate}, FModifierId = #{fModifierId}, FModifyDate = #{fModifyDate}, FApproveDate = #{fApproveDate}, FApproverId = #{fApproverId}, F_cty_Date = #{fctyDate},
WHERE FID = #{fid}

mapper.select:
SELECT re.FID, re.FBillNo, re.FDocumentStatus, re.FBillTypeID, re.FDate, re.FReceiveDeptId, re.FPurOrgId, re.FReceiverId, re.F_jcf, sur.name as FSupplierId, re.F_gcbz, re.F_shdz, re.F_DATE_jz, re.F_djtjcf, sup.name as FSupplyId, re.FProviderContactId, re.FSupplyAddress, supl.name as FSettleId, suple.name as FChargeId, re.FSettleModeId, re.FPayConditionId, bdy.name as FSettleCurrId, re.FAllDisCount, sue.user_name as FCreatorId, re.FCreateDate, se.user_name as FModifierId, re.FModifyDate, re.FApproveDate, sye.user_name as FApproverId, re.F_cty_Date FROM receive_notice re LEFT JOIN sys_user sue on re.FCreatorId=sue.k3_key LEFT JOIN sys_user se on re.FModifierId=se.k3_key LEFT JOIN sys_user sye on re.FApproverId=sye.k3_key LEFT JOIN supplier sur on re.FSupplierId=sur.supplierid LEFT JOIN supplier sup on re.FSupplyId=sup.supplierid LEFT JOIN supplier supl on re.FSettleId=supl.supplierid LEFT JOIN supplier suple on re.FChargeId=suple.supplierid LEFT JOIN bymaterial_dictionary bdy on re.FSettleCurrId=bdy.kingdee and bdy.category='currency'
AND FBillNo LIKE CONCAT('%', #{receiveNotice.fBillNo}, '%')
AND FDocumentStatus = #{receiveNotice.fDocumentStatus}
AND FPurOrgId = #{receiveNotice.fPurOrgId}
AND FSupplierId = #{receiveNotice.fSupplierId}
AND FDate = #{receiveNotice.fDate}
ORDER BY FDate DESC LIMIT #{pageSize} OFFSET #{pageNum}

